    400: "Bad Request",
    401: "Unauthorized",
    403: "Forbidden",
    404: "Not Found",
    405: "Method Not Allowed",
    409: "Conflict",
    410: "Gone",
    422: "Unprocessable Entity",
    429: "Too Many Requests",
    500: "Internal Server Error",
    501: "Not Implemented",
    502: "Bad Gateway",
    503: "Service Unavailable",
    504: "Gateway Timeout",
}

func getStatusMessage(statusCode int) string {
    if message, exists := statusMessages[statusCode]; exists {
        return message
    }
    return "Unknown Status"
}

// Compliant: Structured permission system with maps
type Permission struct {
    Create bool
    Read   bool
    Update bool
    Delete bool
}

var rolePermissions = map[string]Permission{
    "admin": {
        Create: true,
        Read:   true,
        Update: true,
        Delete: true,
    },
    "editor": {
        Create: true,
        Read:   true,
        Update: true,
        Delete: false,
    },
    "viewer": {
        Create: false,
        Read:   true,
        Update: false,
        Delete: false,
    },
    "guest": {
        Create: false,
        Read:   false,
        Update: false,
        Delete: false,
    },
}

func hasPermission(role string, action string) bool {
    permissions, exists := rolePermissions[role]
    if !exists {
        return false
    }

    switch action {
    case "create":
        return permissions.Create
    case "read":
        return permissions.Read
    case "update":
        return permissions.Update
    case "delete":
        return permissions.Delete
    default:
        return false
    }
}

// Compliant: When switch statements are appropriate (small number of cases)
func getLogLevel(level string) int {
    switch strings.ToLower(level) {
    case "debug":
        return 0
    case "info":
        return 1
    case "warn":
        return 2
    case "error":
        return 3
    case "fatal":
        return 4
    default:
        return 1 // Default to info
    }
}

// Compliant: Using interface for complex behavior mapping
type Handler interface {
    Handle() error
}

type CreateHandler struct{}
func (h CreateHandler) Handle() error { return nil }

type UpdateHandler struct{}
func (h UpdateHandler) Handle() error { return nil }

type DeleteHandler struct{}
func (h DeleteHandler) Handle() error { return nil }

var actionHandlers = map[string]Handler{
    "create": CreateHandler{},
    "update": UpdateHandler{},
    "delete": DeleteHandler{},
}

func executeAction(action string) error {
    handler, exists := actionHandlers[action]
    if !exists {
        return errors.New("unknown action")
    }
    return handler.Handle()
}

// Compliant: Factory pattern for complex object creation
type ProcessorFactory struct{}

func (f ProcessorFactory) CreateProcessor(processorType string) (Processor, error) {
    // Map-based factory instead of large switch
    constructors := map[string]func() Processor{
        "json":    func() Processor { return &JSONProcessor{} },
        "xml":     func() Processor { return &XMLProcessor{} },
        "csv":     func() Processor { return &CSVProcessor{} },
        "binary":  func() Processor { return &BinaryProcessor{} },
        "text":    func() Processor { return &TextProcessor{} },
    }

    constructor, exists := constructors[processorType]
    if !exists {
        return nil, errors.New("unsupported processor type")
    }

    return constructor(), nil
}
